import{_ as s,o as a,c as t,ag as e}from"./chunks/framework.ePeAWSvT.js";const l="/images/preparation-checklist.png",g=JSON.parse('{"title":"사전준비 가이드","description":"","frontmatter":{},"headers":[],"relativePath":"사전가이드.md","filePath":"사전가이드.md"}'),i={name:"사전가이드.md"};function d(r,o,c,n,p,u){return a(),t("div",null,[...o[0]||(o[0]=[e('<h1 id="사전준비-가이드" tabindex="-1">사전준비 가이드 <a class="header-anchor" href="#사전준비-가이드" aria-label="Permalink to &quot;사전준비 가이드&quot;">​</a></h1><p>세미나 전날까지 이 페이지의 내용을 완료해 오세요. 당일 설치 때문에 실습 시간을 낭비하지 않으려면 이게 제일 중요합니다.</p><div class="tip custom-block"><p class="custom-block-title">시간이 얼마나 걸리나요?</p><p>순조롭게 진행되면 약 <strong>20~30분</strong> 안에 끝납니다. 혹시 막히는 부분이 있으면 아래 트러블슈팅을 먼저 보시고, 그래도 안 되면 당일 30분 일찍 오세요!</p></div><hr><h2 id="준비물-체크리스트" tabindex="-1">준비물 체크리스트 <a class="header-anchor" href="#준비물-체크리스트" aria-label="Permalink to &quot;준비물 체크리스트&quot;">​</a></h2><p><img src="'+l+'" alt="사전준비 완료 체크리스트"></p><ul><li>[ ] 노트북 (Mac 또는 Windows) + 충전기 — 스마트폰으로는 실습 불가</li><li>[ ] Claude Pro 구독 ($20/월)</li><li>[ ] VS Code 설치</li><li>[ ] Claude Code 설치 &amp; 로그인 확인</li></ul><hr><h2 id="📌-step-1-of-4-claude-pro-구독" tabindex="-1">📌 Step 1 of 4: Claude Pro 구독 <a class="header-anchor" href="#📌-step-1-of-4-claude-pro-구독" aria-label="Permalink to &quot;📌 Step 1 of 4: Claude Pro 구독&quot;">​</a></h2><div class="warning custom-block"><p class="custom-block-title">반드시 해야 합니다</p><p>Claude Code는 <strong>Pro 이상 구독이 필수</strong>입니다. 무료 계정으로는 실행되지 않습니다.</p></div><p>Claude Code를 사용하려면 Claude <strong>Pro 이상</strong> 구독이 필요합니다. 무료 계정으로는 Claude Code를 실행할 수 없습니다.</p><ol><li><a href="https://claude.ai" target="_blank" rel="noreferrer">https://claude.ai</a> 접속</li><li>계정이 없으면 <strong>회원가입</strong> (구글 계정으로 빠르게 가능)</li><li>오른쪽 상단 프로필 → <strong>Upgrade to Pro</strong> → 결제</li><li>월 $20 (약 27,000원). 언제든 해지 가능.</li></ol><div class="tip custom-block"><p class="custom-block-title">이미 Pro이신 분</p><p>로그인 후 화면 왼쪽 하단에 &quot;Claude Pro&quot; 뱃지가 보이면 OK입니다. 바로 Step 2로 넘어가세요.</p></div><div class="info custom-block"><p class="custom-block-title">✅ 여기까지 완료!</p><p>Claude Pro 구독이 되어 있다면 Step 1 끝입니다. 수고하셨어요!</p></div><hr><h2 id="📌-step-2-of-4-vs-code-설치" tabindex="-1">📌 Step 2 of 4: VS Code 설치 <a class="header-anchor" href="#📌-step-2-of-4-vs-code-설치" aria-label="Permalink to &quot;📌 Step 2 of 4: VS Code 설치&quot;">​</a></h2><div class="warning custom-block"><p class="custom-block-title">반드시 해야 합니다</p><p>Claude Code를 가장 편하게 사용하는 편집기입니다. 코딩 몰라도 괜찮아요 — 오늘은 AI와 대화하는 창으로만 씁니다.</p></div><h3 id="mac" tabindex="-1">Mac <a class="header-anchor" href="#mac" aria-label="Permalink to &quot;Mac&quot;">​</a></h3><ol><li><a href="https://code.visualstudio.com" target="_blank" rel="noreferrer">https://code.visualstudio.com</a> 접속</li><li><strong>Download for Mac</strong> 클릭</li><li>다운로드된 <code>.zip</code> 파일 더블클릭 → <code>Visual Studio Code.app</code> 생성</li><li><code>Visual Studio Code.app</code>을 <strong>응용 프로그램(Applications) 폴더로 드래그</strong></li><li>응용 프로그램에서 VS Code 실행</li></ol><h3 id="windows" tabindex="-1">Windows <a class="header-anchor" href="#windows" aria-label="Permalink to &quot;Windows&quot;">​</a></h3><ol><li><a href="https://code.visualstudio.com" target="_blank" rel="noreferrer">https://code.visualstudio.com</a> 접속</li><li><strong>Download for Windows</strong> 클릭</li><li>다운로드된 <code>.exe</code> 파일 실행</li><li>설치 옵션은 <strong>기본값 그대로</strong> 다음 → 다음 → 설치</li><li>설치 완료 후 VS Code 실행</li></ol><p><strong>설치 확인:</strong> VS Code를 열었을 때 아래와 같은 시작 화면이 보이면 성공입니다.</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Welcome to Visual Studio Code</span></span></code></pre></div><div class="info custom-block"><p class="custom-block-title">✅ 여기까지 완료!</p><p>VS Code 시작 화면이 보인다면 Step 2 끝입니다. 거의 다 왔어요!</p></div><hr><h2 id="📌-step-3-of-4-claude-code-설치" tabindex="-1">📌 Step 3 of 4: Claude Code 설치 <a class="header-anchor" href="#📌-step-3-of-4-claude-code-설치" aria-label="Permalink to &quot;📌 Step 3 of 4: Claude Code 설치&quot;">​</a></h2><div class="tip custom-block"><p class="custom-block-title">이건 안 해도 됩니다 (방법 B)</p><p>방법 A가 더 쉽습니다. 방법 A를 먼저 시도하고, 안 될 때만 방법 B로 넘어가세요.</p></div><p>Claude Code를 설치하는 방법은 두 가지입니다. <strong>방법 A가 더 쉽습니다.</strong> 방법 A를 먼저 시도하세요.</p><h3 id="방법-a-vs-code-확장으로-설치-추천" tabindex="-1">방법 A: VS Code 확장으로 설치 (추천) <a class="header-anchor" href="#방법-a-vs-code-확장으로-설치-추천" aria-label="Permalink to &quot;방법 A: VS Code 확장으로 설치 (추천)&quot;">​</a></h3><p>터미널을 열 필요 없이 VS Code 안에서 바로 설치하는 방법입니다.</p><ol><li>VS Code 실행</li><li>왼쪽 사이드바에서 <strong>네모 4개 모양 아이콘</strong> (Extensions) 클릭 <ul><li>단축키: <code>Ctrl+Shift+X</code> (Windows) / <code>Cmd+Shift+X</code> (Mac)</li></ul></li><li>상단 검색창에 <strong><code>Claude Code</code></strong> 입력</li><li>목록에서 <strong>&quot;Claude Code&quot; — Anthropic</strong> 찾기</li><li><strong>Install</strong> 버튼 클릭</li><li>설치 완료 후 왼쪽 사이드바에 <strong>Claude 아이콘(사람 모양)</strong> 이 생기면 성공</li></ol><div class="tip custom-block"><p class="custom-block-title">아이콘이 안 보이면</p><p>설치 후 VS Code를 완전히 종료하고 다시 열어보세요. 그래도 없으면 왼쪽 사이드바 빈 공간에서 우클릭 → Claude Code 체크.</p></div><hr><h3 id="방법-b-터미널로-설치-방법-a가-안-될-때" tabindex="-1">방법 B: 터미널로 설치 (방법 A가 안 될 때) <a class="header-anchor" href="#방법-b-터미널로-설치-방법-a가-안-될-때" aria-label="Permalink to &quot;방법 B: 터미널로 설치 (방법 A가 안 될 때)&quot;">​</a></h3><div class="warning custom-block"><p class="custom-block-title">방법 A가 안 될 때만 이 방법을 사용하세요</p><p>이 방법은 Node.js가 필요합니다.</p></div><p><strong>Node.js 먼저 설치 (없는 경우)</strong></p><ol><li><a href="https://nodejs.org" target="_blank" rel="noreferrer">https://nodejs.org</a> 접속</li><li><strong>LTS</strong> 버전 다운로드 (왼쪽 버튼, 안정적인 버전)</li><li>다운로드된 파일 실행 → 기본 옵션으로 설치</li></ol><p><strong>Claude Code 설치 명령어</strong></p><ul><li><strong>Mac:</strong> <code>터미널</code> 앱 열기 (Spotlight에서 &quot;terminal&quot; 검색)</li><li><strong>Windows:</strong> <code>PowerShell</code> 앱 열기 (시작 메뉴에서 &quot;powershell&quot; 검색)</li></ul><p>터미널/PowerShell에 아래를 입력하고 Enter:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">npm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -g</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> @anthropic-ai/claude-code</span></span></code></pre></div><p>설치가 완료되면 아래 명령어로 확인:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">claude</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --version</span></span></code></pre></div><p>버전 번호가 나오면 성공입니다.</p><div class="info custom-block"><p class="custom-block-title">✅ 여기까지 완료!</p><p>Claude 아이콘이 VS Code에 보이거나, 터미널에서 버전 번호가 나왔다면 Step 3 끝입니다!</p></div><hr><h2 id="📌-step-4-of-4-로그인-확인" tabindex="-1">📌 Step 4 of 4: 로그인 확인 <a class="header-anchor" href="#📌-step-4-of-4-로그인-확인" aria-label="Permalink to &quot;📌 Step 4 of 4: 로그인 확인&quot;">​</a></h2><div class="warning custom-block"><p class="custom-block-title">반드시 해야 합니다</p><p>설치 후 반드시 로그인까지 확인해야 세미나 당일 바로 실습할 수 있습니다.</p></div><p>설치가 끝났으면 실제로 작동하는지 확인합니다.</p><p><strong>VS Code 확장 방법으로 설치한 경우:</strong></p><ol><li>VS Code 왼쪽 Claude 아이콘 클릭</li><li><strong>Sign in</strong> 버튼 클릭 → 브라우저에서 Claude 계정으로 로그인</li><li>VS Code로 돌아와서 채팅창에 <strong><code>안녕!</code></strong> 입력</li><li>Claude가 응답하면 완료!</li></ol><p><strong>터미널 방법으로 설치한 경우:</strong></p><ol><li>터미널에서 <code>claude</code> 입력 후 Enter</li><li>처음 실행 시 로그인 프롬프트 → 브라우저 열림 → 로그인</li><li>터미널로 돌아와서 <strong><code>안녕!</code></strong> 입력</li><li>응답이 오면 완료!</li></ol><div class="tip custom-block"><p class="custom-block-title">성공 기준</p><p>Claude가 &quot;안녕하세요!&quot; 같은 응답을 돌려주면 모든 준비가 끝난 겁니다.</p></div><div class="info custom-block"><p class="custom-block-title">✅ 여기까지 완료!</p><p>Claude가 &quot;안녕하세요!&quot;라고 응답했다면 Step 4 끝입니다. 완벽해요!</p></div><hr><h2 id="🎉-모든-준비-끝-세미나-당일-편하게-오세요" tabindex="-1">🎉 모든 준비 끝! 세미나 당일 편하게 오세요 <a class="header-anchor" href="#🎉-모든-준비-끝-세미나-당일-편하게-오세요" aria-label="Permalink to &quot;🎉 모든 준비 끝! 세미나 당일 편하게 오세요&quot;">​</a></h2><p>4단계를 모두 마치셨군요! 정말 수고 많으셨습니다. 세미나 당일에는 노트북과 충전기만 챙겨 오시면 됩니다. 실습 내용이 더 기대되시죠? 당일에 뵙겠습니다! 😊</p><hr><h2 id="트러블슈팅-자주-발생하는-문제" tabindex="-1">트러블슈팅 (자주 발생하는 문제) <a class="header-anchor" href="#트러블슈팅-자주-발생하는-문제" aria-label="Permalink to &quot;트러블슈팅 (자주 발생하는 문제)&quot;">​</a></h2><p>막히는 게 생기면 아래를 먼저 확인해 보세요.</p><details class="details custom-block"><summary><code>command not found: npm</code> 오류</summary><p><strong>원인:</strong> Node.js가 설치되어 있지 않습니다.</p><p><strong>해결:</strong> <a href="https://nodejs.org" target="_blank" rel="noreferrer">nodejs.org</a>에서 LTS 버전을 설치한 뒤, 터미널을 완전히 종료하고 다시 열어 명령어를 입력하세요.</p></details><details class="details custom-block"><summary><code>permission denied</code> 오류</summary><p><strong>원인:</strong> 현재 계정에 설치 권한이 없습니다.</p><p><strong>해결:</strong></p><ul><li>Mac: 명령어 앞에 <code>sudo </code> 를 붙여 입력 (예: <code>sudo npm install -g @anthropic-ai/claude-code</code>)</li><li>Windows: PowerShell을 &quot;관리자 권한으로 실행&quot;하여 다시 시도</li></ul></details><details class="details custom-block"><summary>로그인해도 &quot;구독이 필요합니다&quot; 메시지</summary><p><strong>원인:</strong> Claude Pro 구독이 되어 있지 않습니다.</p><p><strong>해결:</strong> <a href="https://claude.ai" target="_blank" rel="noreferrer">claude.ai</a> 접속 후 왼쪽 하단의 구독 상태를 확인하고, Pro로 업그레이드하세요.</p></details><details class="details custom-block"><summary>VS Code 확장 검색에 Claude Code가 안 나옴</summary><p><strong>원인:</strong> 검색어에 오타가 있거나 인터넷 연결이 불안정합니다.</p><p><strong>해결:</strong> <code>Claude Code</code> 를 정확히 입력하세요 (대소문자 무관, 공백 포함). 그래도 안 나오면 VS Code를 재시작 후 다시 시도하세요.</p></details><details class="details custom-block"><summary>브라우저 로그인 후 VS Code에 반응 없음</summary><p><strong>원인:</strong> 브라우저 팝업이 차단되었습니다.</p><p><strong>해결:</strong> 브라우저 주소창 오른쪽의 팝업 차단 아이콘을 클릭해 허용으로 바꾼 뒤 다시 시도하세요.</p></details><details class="details custom-block"><summary>Mac에서 &quot;개발자를 확인할 수 없음&quot; 경고</summary><p><strong>원인:</strong> macOS 보안 설정이 앱 실행을 막고 있습니다.</p><p><strong>해결:</strong> 시스템 설정 → 개인 정보 보호 및 보안 → 화면 하단 &quot;그래도 열기&quot; 클릭</p></details><hr><h2 id="안-되면" tabindex="-1">안 되면? <a class="header-anchor" href="#안-되면" aria-label="Permalink to &quot;안 되면?&quot;">​</a></h2><p>막히는 부분이 있어도 걱정하지 마세요. 두 가지 방법으로 해결할 수 있습니다.</p><p><strong>방법 1: 당일 일찍 오기</strong> 세미나 시작 30분 전에 오시면 1:1로 직접 도와드립니다. 이 방법이 제일 빠릅니다.</p><p><strong>방법 2: 사전에 스크린샷 보내기</strong> 오류 화면을 캡처해서 카톡으로 보내주시면 미리 해결책을 알려드립니다.</p><div class="warning custom-block"><p class="custom-block-title">당일 설치는 피해주세요</p><p>당일 설치가 시작되면 다른 참가자분들의 실습 시간이 줄어듭니다. 꼭 전날까지 완료해 주세요. 정말 안 되시면 일찍 오시는 방법을 이용해 주세요!</p></div>',73)])])}const m=s(i,[["render",d]]);export{g as __pageData,m as default};
